import { useEffect, useState } from "react";
import { Footer } from "./Footer";
import { NavBar } from "./NavBar";
import pattern from "../slike/pattern4.jpg";

export function PocetnaGosti() {
    const [sobe, setSobe] = useState([]);
    const [filterSlobodne, setFilterSlobodne] = useState(false);
    const [filterTip, setFilterTip] = useState("");
    const [pretraga, setPretraga] = useState("");
    const [tipoviSoba, setTipoviSoba] = useState([]);

    // Ucitavanje soba i tipova soba iz backenda
    useEffect(() => {
        fetch("http://localhost:8080/rooms/all")
            .then((res) => res.json())
            .then((data) => {
                if (data && data.data && data.data.values) {
                    setSobe(data.data.values);
                }
            })
            .catch((err) => console.error("Greška pri učitavanju soba:", err));

        // Učitavanje tipova soba
        fetch("http://localhost:8080/roomTypes/all")
            .then((res) => res.json())
            .then((data) => {
                if (data && data.data && data.data.values) {
                    setTipoviSoba(data.data.values);
                }
            })
            .catch((err) => console.error("Greška pri učitavanju tipova soba:", err));
    }, []);

    // Dohvatanje ID i email gosta iz cookie-a
    const getGuestFromCookie = () => {
        const cookies = document.cookie.split("; ").reduce((acc, curr) => {
            const [key, value] = curr.split("=");
            acc[key] = value;
            return acc;
        }, {});
        return { idGost: parseInt(cookies.userId), email: cookies.userEmail };
    };

    const kreirajRezervaciju = async (soba) => {
        const gost = getGuestFromCookie();

        if (!gost.idGost) {
            alert("Nije pronadjen ulogovani gost!");
            return;
        }

        const rezervacija = {
            datumPrijave: new Date().toISOString().split("T")[0],
            datumOdjave: new Date().toISOString().split("T")[0],
            brojOsoba: 1,
            ukupanIznos: soba.tipSobe ? soba.tipSobe.cenaPoNoci : 3000,
            statusRezervacije: "ZAHTEVANO", // status za recepcionara
            datumKreiranja: new Date().toISOString().split("T")[0],
            gost: { idGost: gost.idGost },
            soba: { idSoba: soba.idSoba },
            recepcionar: null
        };

        try {
            const response = await fetch("http://localhost:8080/reservations/add", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(rezervacija),
            });

            if (response.ok) {
                alert("Zahtev za rezervaciju poslat recepcionaru!");
            } else {
                alert("Rezervacija ne može biti kreirana.");
            }
        } catch (error) {
            console.error("Greška pri kreiranju rezervacije:", error);
            alert("Server nije dostupan.");
        }
    };

    // Filtriranje soba
    const filtriraneSobe = sobe.filter((soba) => {
        if (filterSlobodne && !soba.dostupna) return false;
        if (filterTip && soba.tipSobe?.naziv !== filterTip) return false;
        if (pretraga && !soba.naziv.toLowerCase().includes(pretraga.toLowerCase())) return false;
        return true;
    });

    return (
        <>
            <NavBar />
            <div
                style={{
                    backgroundImage: `url(${pattern})`,
                    backgroundSize: "cover",
                    backgroundPosition: "center",
                    minHeight: "100vh",
                    padding: "40px",
                }}
            >
                <h2
                    style={{
                        textAlign: "center",
                        color: "white",
                        backgroundColor: "rgba(225, 105, 255, 0.6)",
                        padding: "15px 30px",
                        borderRadius: "10px",
                        display: "inline-block",
                    }}
                >
                    Lista soba
                </h2>

                {/* Filter i pretraga */}
                <div
                    style={{
                        display: "flex",
                        justifyContent: "center", // centriranje
                        alignItems: "center",
                        gap: "15px",
                        margin: "20px 0",
                        flexWrap: "wrap"
                    }}
                >
                    <label>
                        <input
                            type="checkbox"
                            checked={filterSlobodne}
                            onChange={(e) => setFilterSlobodne(e.target.checked)}
                        />
                        Prikaži samo slobodne
                    </label>

                    <select
                        value={filterTip}
                        onChange={(e) => setFilterTip(e.target.value)}
                        style={{ padding: "5px", borderRadius: "5px" }}
                    >
                        <option value="">Svi tipovi</option>
                        {tipoviSoba.length > 0 ? (
                            tipoviSoba.map((t) => (
                                <option key={t.idTipSobe} value={t.naziv}>
                                    {t.naziv}
                                </option>
                            ))
                        ) : (
                            <option disabled>Učitavanje tipova...</option>
                        )}
                    </select>

                    <input
                        type="text"
                        placeholder="Pretraži po nazivu sobe"
                        value={pretraga}
                        onChange={(e) => setPretraga(e.target.value)}
                        style={{ padding: "5px", borderRadius: "5px" }}
                    />
                </div>

                {/* Prikaz soba */}
                <div
                    style={{
                        display: "flex",
                        flexWrap: "wrap",
                        justifyContent: "center",
                        gap: "20px",
                    }}
                >
                    {filtriraneSobe.map((soba) => (
                        <div
                            key={soba.idSoba}
                            style={{
                                backgroundColor: "rgba(255,255,255,1)",
                                width: "250px",
                                borderRadius: "15px",
                                padding: "15px",
                                boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
                                textAlign: "center",
                            }}
                        >
                            {soba.slika && (
                                <img
                                    src={`http://localhost:8080/uploads/${soba.slika.split("/").pop()}`}
                                    alt="Slika sobe"
                                    style={{ width: "100%", height: "150px", borderRadius: "10px", objectFit: "cover" }}
                                />
                            )}
                            <h3>{soba.naziv}</h3>
                            <p>Tip sobe: {soba.tipSobe?.naziv || "Nepoznat"}</p>
                            <p>Dostupna: {soba.dostupna ? "Da" : "Ne"}</p>
                            <p>
                                Cena po noći: {soba.tipSobe ? soba.tipSobe.cenaPoNoci + " RSD" : "3000 RSD"}
                            </p>
                            <button
                                onClick={() => kreirajRezervaciju(soba)}
                                className="btnNav"
                                style={{
                                    marginTop: "10px",
                                    border: "none",
                                    fontSize: "16px",
                                    width: "160px",
                                    height: "40px",
                                }}
                            >
                                Zahtevaj rezervaciju
                            </button>
                        </div>
                    ))}
                </div>
            </div>
            <Footer />
        </>
    );
}
